import json
import pandas as pd

path = 'other-benchmarks/Kramabench/data/wildfire/input/nifc_human_caused_acres.csv'
df = pd.read_csv(path, sep='\t')
df.columns = df.columns.str.replace('*', '', regex=False)
geo_cols = [col for col in df.columns if col not in ['Year', 'Total']]
records = {}
for _, row in df.iterrows():
    year = int(row['Year'])
    records[year] = {}
    for col in geo_cols:
        value = str(row[col])
        if value == 'N/A':
            records[year][col] = None
        else:
            records[year][col] = float(value.replace(',', ''))
print(json.dumps(records, sort_keys=True, separators=(',', ':')))

